import "@radix-ui/themes/styles.css";
import { Card, AspectRatio, Text, Link, Flex, Heading } from "@radix-ui/themes";
import './App.css';
import ProjectsCard from "./ProjectsCard";

const Projects = (props) => {
    return (
        <Link>
            <Card padding="2rem">
                <Flex direction="row" gap="1rem">
                    <AspectRatio ratio={16 / 9} style={{ overflow: "hidden" }} width="20px">
                        <img src="/evesubsystemanalysis.png" alt="Project 1" style={{ borderRadius: "5px", width: "100%", height: "100%", objectFit: "cover" }} />
                    </AspectRatio>
                    <Flex direction="column" gap="1rem">
                        <Text size="2" weight="bold">Project 1</Text>
                        <Text size="1" style={{ color: "#0000009e" }}>This is a description of project 1</Text>
                    </Flex>
                </Flex>
            </Card>
        </Link>
    );
};

export default Projects;
